import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { api, setAuthToken } from "../api";
import "../styles/auth.css";

export default function Login() {
  const navigate = useNavigate();
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [emailForOtp, setEmailForOtp] = useState("");
  const [otpCode, setOtpCode] = useState("");
  const [showEmailVerificationTools, setShowEmailVerificationTools] = useState(false);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      setError("");
      setMessage("");
      setShowEmailVerificationTools(false);
      setLoading(true);
      const res = await api.post("/auth/login/", { identifier, password });
      setAuthToken(res.data.token);
      setLoading(false);
      navigate("/home");
    } catch (err) {
      setLoading(false);
      const detail = err.response?.data?.detail || "Login failed. Please try again.";
      setError(detail);
      if (String(detail).toLowerCase().includes("verify your email")) {
        setShowEmailVerificationTools(true);
      }
    }
  };

  const resendEmailOtp = async () => {
    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/send-email-otp/", { email: emailForOtp.trim() });
      setLoading(false);
      setMessage("OTP sent. Check your email (or backend terminal in local mode).");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to send OTP.");
    }
  };

  const verifyEmailOtp = async () => {
    try {
      setError("");
      setMessage("");
      setLoading(true);
      await api.post("/auth/verify-email-otp/", {
        email: emailForOtp.trim(),
        code: otpCode.trim(),
      });
      setLoading(false);
      setMessage("Email verified successfully. You can sign in now.");
      setShowEmailVerificationTools(false);
      setOtpCode("");
    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.detail || "Unable to verify OTP.");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <div className="auth-header">
          <h1>Welcome Back</h1>
          <p>Sign in to continue to your account.</p>
        </div>

        <form onSubmit={handleLogin} className="auth-form">
          <div className="form-group">
              <label htmlFor="identifier">Username / Email / Mobile</label>
            <input
              id="identifier"
              type="text"
              placeholder="Enter username, email, or mobile number"
              value={identifier}
              onChange={(e) => setIdentifier(e.target.value)}
              required
            />
            <div className="input-focus"></div>
            <p>
              <Link to="/forgot-username" className="auth-link">Forgot username?</Link>
            </p>
          </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
              placeholder="Enter your password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
            <div className="input-focus"></div>
            <p>
              <Link to="/forgot-password" className="auth-link">Forgot password?</Link>
            </p>
          </div>

          {error && <div className="error-box">{error}</div>}
          {message && <div className="success-message">{message}</div>}

          <button type="submit" className="btn-login" disabled={loading}>
            {loading ? "Signing in..." : "Sign In"}
          </button>

          {showEmailVerificationTools && (
            <div style={{ marginTop: 12 }}>
              <div className="form-group">
                <label htmlFor="emailForOtp">Email for OTP</label>
                <input
                  id="emailForOtp"
                  type="email"
                  placeholder="Enter your registered email"
                  value={emailForOtp}
                  onChange={(e) => setEmailForOtp(e.target.value)}
                  required
                />
                <div className="input-focus"></div>
              </div>

              <div className="form-group">
                <label htmlFor="otpCode">Email OTP</label>
                <input
                  id="otpCode"
                  type="text"
                  placeholder="Enter OTP"
                  value={otpCode}
                  onChange={(e) => setOtpCode(e.target.value)}
                />
                <div className="input-focus"></div>
              </div>

              <button
                type="button"
                className="btn-login"
                onClick={resendEmailOtp}
                disabled={loading || !emailForOtp.trim()}
              >
                Resend OTP
              </button>
              <button
                type="button"
                className="btn-signup"
                style={{ marginTop: 8 }}
                onClick={verifyEmailOtp}
                disabled={loading || !emailForOtp.trim() || !otpCode.trim()}
              >
                Verify OTP
              </button>
            </div>
          )}
        </form>

        <div className="auth-footer">
          <p>Use your account to continue shopping and managing orders.</p>
          <p>Don't have an account? <Link to="/signup" className="auth-link">Sign Up</Link></p>
        </div>
      </div>
    </div>
  );
}
